    /* Estética técnica profesional para eXeLearning */
    .mi-curacion-asir-legal {
        font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        background-color: #f9f9f9;
        color: #333;
        padding: 25px;
        border-radius: 10px;
